// Validate and prepare attachments from Discord bot payload
const body = $input.first().json.body || $input.first().json;
const attachments = body.attachments || (body.attachment_url ? [{ attachment_url: body.attachment_url, filename: body.filename || 'invoice', content_type: body.content_type || 'image/png', file_size: body.file_size }] : []);

if (!attachments.length) {
  throw new Error('No attachments in payload');
}

return [{
  json: {
    attachments,
    channel_id: body.channel_id,
    message_id: body.message_id,
    author: body.author,
    message_content: body.message_content || ''
  }
}];

// Detect file type: Excel vs image (Claude vision only supports images)
const item = $input.first();
const binaryKey = Object.keys(item.binary || {})[0] || 'data';
const bin = item.binary?.[binaryKey];
if (!bin) throw new Error('No binary data');

const mime = (bin.mimeType || '').toLowerCase();
const excelTypes = ['application/vnd.openxmlformats-officedocument.spreadsheetml.sheet','application/vnd.ms-excel','application/vnd.oasis.opendocument.spreadsheet'];
const isExcel = excelTypes.includes(mime) || /\.(xlsx|xls|ods)$/i.test(item.json?.filename || '');

return [{ json: { ...item.json, isExcel }, binary: item.binary }];

// Format Excel rows as text and build Claude request (text-only, no image)
const items = $input.all();
const rows = items.map(i => {
  const r = i.json?.row || i.json;
  if (!r || typeof r !== 'object') return null;
  const vals = Object.keys(r).sort((a,b)=>Number(a)-Number(b)).map(k=>r[k]);
  return vals.join('\t');
}).filter(Boolean);
const spreadsheetText = rows.join('\n');

const prompt = 'Below is spreadsheet data from a K-pop vendor invoice. Extract all line items. Return ONLY valid JSON, no markdown.\n\nFor each line item: vendor_notation, quantity, unit_price, total_price, line_number.\nFrom header: vendor_name, invoice_number, invoice_date.\n\nReturn: { "vendor_name": "...", "invoice_number": "...", "invoice_date": "...", "line_items": [{ "vendor_notation": "...", "quantity": 1, "unit_price": 18.50, "total_price": 18.50 }] }';

const fullText = 'SPREADSHEET DATA:\n' + spreadsheetText + '\n\n' + prompt;

const systemMsg = 'You are an invoice extraction assistant for K-pop vendor invoices. Extract ONLY the relevant product line items. Ignore headers, footers, totals, subtotals, shipping, tax, and other non-product rows. Include only rows that represent actual product purchases (quantity, unit price, total price).';

const requestBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  system: systemMsg,
  messages: [{ role: 'user', content: [{ type: 'text', text: fullText }] }]
};

return [{ json: { requestBody } }];

// Convert binary to base64 and build Claude request for images
const item = $input.first();
const binaryKey = Object.keys(item.binary || {})[0] || 'data';
const bin = item.binary?.[binaryKey];
if (!bin) throw new Error('No binary data');

const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const base64 = buffer.toString('base64');
let mimeType = (bin.mimeType || 'image/png').toLowerCase();
if (mimeType === 'image/jpg') mimeType = 'image/jpeg';
const allowed = ['image/jpeg','image/png','image/gif','image/webp'];
if (!allowed.includes(mimeType)) {
  throw new Error('Unsupported format: ' + (bin.mimeType || 'unknown') + '. Use image (PNG, JPEG, GIF, WebP) or Excel (XLSX).');
}

const prompt = 'Extract all line items from this K-pop vendor invoice. Return ONLY valid JSON, no markdown.\n\nFor each line item: vendor_notation, quantity, unit_price, total_price, line_number.\nFrom header: vendor_name, invoice_number, invoice_date.\n\nReturn: { "vendor_name": "...", "invoice_number": "...", "invoice_date": "...", "line_items": [{ "vendor_notation": "...", "quantity": 1, "unit_price": 18.50, "total_price": 18.50 }] }';

const systemMsg = 'You are an invoice extraction assistant for K-pop vendor invoices. Extract ONLY the relevant product line items. Ignore headers, footers, totals, subtotals, shipping, tax, and other non-product rows. Include only rows that represent actual product purchases (quantity, unit price, total price).';

const requestBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  system: systemMsg,
  messages: [{
    role: 'user',
    content: [
      { type: 'image', source: { type: 'base64', media_type: mimeType, data: base64 } },
      { type: 'text', text: prompt }
    ]
  }]
};

return [{ json: { requestBody } }];

// Parse Claude response and extract line_items
const item = $input.first().json;
let text = '';
if (item.content && Array.isArray(item.content)) {
  const block = item.content.find(c => c.type === 'text');
  text = block ? block.text : JSON.stringify(item.content);
} else if (typeof item.text === 'string') {
  text = item.text;
} else {
  text = JSON.stringify(item);
}

let json;
const match = text.match(/```(?:json)?\s*([\s\S]*?)```/) || text.match(/\{[\s\S]*\}/);
if (match) {
  const raw = match[1] ? match[1].trim() : match[0];
  json = JSON.parse(raw);
} else {
  json = JSON.parse(text);
}

const lineItems = json.line_items || [];
const vendorName = json.vendor_name || '';
const invoiceNumber = json.invoice_number || '';
const invoiceDate = json.invoice_date || '';

return lineItems.map((li, i) => ({
  json: {
    ...li,
    vendor_name: vendorName,
    invoice_number: invoiceNumber,
    invoice_date: invoiceDate,
    line_number: li.line_number ?? i + 1
  }
}));

// Aggregate all line items from all attachments
const items = $input.all();
const allLineItems = [];
for (const item of items) {
  const j = item.json;
  if (j && j.vendor_notation) allLineItems.push(j);
  else if (j && Array.isArray(j)) j.forEach(li => allLineItems.push(li));
}
return allLineItems.map(li => ({ json: li }));

// Build callback payload for bot to reply to original Discord message
const items = $input.all();
const lineItems = items.flatMap(i => i.json.line_items || [i.json]);
const fromCache = items.filter(i => i.json.from_cache).length;
const fromAi = items.filter(i => !i.json.from_cache).length;
const discordMessage = `Parsed ${lineItems.length} line items. ${fromCache} from cache, ${fromAi} identified by AI.`;
const prep = $('Prepare Attachments').first().json;
return [{ json: {
  channel_id: prep.channel_id,
  message_id: prep.message_id,
  discord_message: discordMessage,
  line_items: lineItems,
  standard_vendor_id: lineItems[0]?.standard_vendor_id,
  vendor_name: lineItems[0]?.vendor_name || ''
} }];
